        this->on(evt->get<delayed_store_t>());
        break;
    case event_id::update_fcsr_flags:
        this->on(evt->get<update_fcsr_flags_t>());
        break;
    case event_id::delayed_write_fp:
        this->on(evt->get<delayed_write_fp_t>());
        break;
    case event_id::vpu_rf_update:
        this->on(evt->get<vpu_rf_update_t>());
        break;
    case event_id::delayed_write_rm:
        this->on(evt->get<delayed_write_rm_t>());
        break;
    case event_id::ipi_received:
        this->on(evt->get<ipi_received_t>());
        break;
    case event_id::tensorfma_write:
        this->on(evt->get<tensorfma_write_t>());
        break;
    case event_id::tensorfma_write8:
        this->on(evt->get<tensorfma_write8_t>());
        break;
    case event_id::tensorquant_write:
        this->on(evt->get<tensorquant_write_t>());
        break;
    case event_id::reduce_write:
        this->on(evt->get<reduce_write_t>());
        break;
    case event_id::tensorstore_write:
        this->on(evt->get<tensorstore_write_t>());
        break;
    case event_id::tensorfma_done:
        this->on(evt->get<tensorfma_done_t>());
        break;
    case event_id::tensorquant_done:
        this->on(evt->get<tensorquant_done_t>());
        break;
    case event_id::reduce_done:
        this->on(evt->get<reduce_done_t>());
        break;
    case event_id::tensorstore_done:
        this->on(evt->get<tensorstore_done_t>());
        break;
    case event_id::tl_mon_op_start:
        this->on(evt->get<tl_mon_op_start_t>());
        break;
    case event_id::tl_mon_process_busy:
        this->on(evt->get<tl_mon_process_busy_t>());
        break;
    case event_id::tl_mon_process_req:
        this->on(evt->get<tl_mon_process_req_t>());
        break;
    case event_id::tl_mon_process_resp:
        this->on(evt->get<tl_mon_process_resp_t>());
